  1852→bool nsCSPPolicy::allows(CSPDirective aDirective, enum CSPKeyword aKeyword,
  1853→                         const nsAString& aHashOrNonce) const {
  1854→  CSPUTILSLOG(("nsCSPPolicy::allows, aKeyWord: %s, a HashOrNonce: %s",
  1855→               CSP_EnumToUTF8Keyword(aKeyword),
  1856→               NS_ConvertUTF16toUTF8(aHashOrNonce).get()));
  1857→
  1858→  if (nsCSPDirective* directive = matchingOrDefaultDirective(aDirective)) {
  1859→    return directive->allows(aKeyword, aHashOrNonce);
  1860→  }
  1861→
  1862→  // No matching directive or default directive as fallback found, thus
  1863→  // allowing the load; see Bug 885433
  1864→  // a) inline scripts (also unsafe eval) should only be blocked
  1865→  //    if there is a [script-src] or [default-src]
  1866→  // b) inline styles should only be blocked
  1867→  //    if there is a [style-src] or [default-src]
  1868→  return true;
  1869→}
  1870→
  1871→nsCSPDirective* nsCSPPolicy::matchingOrDefaultDirective(
  1872→    CSPDirective aDirective) const {
  1873→  nsCSPDirective* defaultDir = nullptr;
  1874→
  1875→  // Try to find a matching directive
  1876→  for (uint32_t i = 0; i < mDirectives.Length(); i++) {
  1877→    if (mDirectives[i]->isDefaultDirective()) {
  1878→      defaultDir = mDirectives[i];
  1879→      continue;
  1880→    }
  1881→    if (mDirectives[i]->equals(aDirective)) {
  1882→      return mDirectives[i];
  1883→    }
  1884→  }
  1885→
  1886→  return defaultDir;
  1887→}
